class Solution {
public:
    Solution(int m, int n) {
        M = m;
        N = n;
        matrix = vector<vector<bool>>(m, vector<bool>(n, 0));
    }

    vector<int> flip() {
        while (true) {
            int i = rand() % M;
            int j = rand() % N;
            if (!matrix[i][j]) {
                matrix[i][j] = 1;
                return {i, j};
            }
        }
    }

    void reset() {
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                matrix[i][j] = 0;
            }
        }
    }
private:
    int M, N;
    vector<vector<bool>> matrix;
};
